import{_ as e,o as a,c as t,a2 as i}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"📊 市場情緒日報 — 2026年5月28日（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260528.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260528.md"}'),n={name:"Deep32Q知識庫/市場情緒/市場情緒_20260528.md"};function o(s,r,l,c,h,g){return a(),t("div",null,[...r[0]||(r[0]=[i('<h1 id="📊-市場情緒日報-—-2026年5月28日-週四" tabindex="-1">📊 市場情緒日報 — 2026年5月28日（週四） <a class="header-anchor" href="#📊-市場情緒日報-—-2026年5月28日-週四" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026年5月28日（週四）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-28 05:00 = 2026-05-27 21:00 UTC) <strong>敘事錨點</strong>：🔴🔴🔴 伊朗宣稱與美國達成「1個月內恢復荷莫茲海峽每日100艘通航」MOU框架 → Trump駁斥為「完全捏造」→ 市場在和平希望與不確定性之間拉鋸</p></blockquote><hr><h2 id="🔑-今日最大事件-前3點深度敘事" tabindex="-1">🔑 今日最大事件（前3點深度敘事） <a class="header-anchor" href="#🔑-今日最大事件-前3點深度敘事" aria-label="Permalink to &quot;🔑 今日最大事件（前3點深度敘事）&quot;">​</a></h2><h3 id="_1-🇺🇸🇮🇷-伊朗宣佈-mou-框架-1個月恢復100艘-日-→-trump-「完全是捏造」" tabindex="-1">1. 🇺🇸🇮🇷 伊朗宣佈 MOU 框架：1個月恢復100艘/日 → Trump：「完全是捏造」 <a class="header-anchor" href="#_1-🇺🇸🇮🇷-伊朗宣佈-mou-框架-1個月恢復100艘-日-→-trump-「完全是捏造」" aria-label="Permalink to &quot;1. 🇺🇸🇮🇷 伊朗宣佈 MOU 框架：1個月恢復100艘/日 → Trump：「完全是捏造」&quot;">​</a></h3><ul><li><strong>最新動態</strong>（5/27）：伊朗國家電視台報導美伊已達成「備忘錄框架」（MoU），伊朗承諾在1個月內將荷莫茲海峽通航恢復至戰前水準（每日100-120艘），條件為美國撤軍+解除海軍封鎖。伊朗與阿曼共同管理海峽航運。</li><li><strong>白宮回應</strong>：Trump與白宮直接否認，稱伊朗報導為「完全捏造」（&quot;a complete fabrication&quot;），強調「重大問題尚未解決」。</li><li><strong>Rubio表態</strong>：國務卿Rubio表示「謹慎樂觀」（cautious optimism），但承認最終協議尚未簽署。</li><li><strong>當前通航實況</strong>：5/27 當日僅有 23 艘船隻在伊朗許可下通過海峽，遠低於戰前每日 125-140 艘。美軍自 4/13 封鎖以來已重導 100 艘商船。</li><li><strong>影響鏈</strong>：此消息直接驅動油價當日大跌 6%+、股市衝高、金價下跌。但 Trump 否認後，市場仍處高度不確定。</li><li><strong>關鍵節點</strong>：本週持續關注伊朗是否正式簽署 MOU，以及 Trump 政府的實際談判立場。</li><li>來源：<a href="https://www.iranintl.com/en/202605270408" target="_blank" rel="noreferrer">Iran International</a> · <a href="https://www.foxnews.com/live-news/iran-irgc-donald-trump-war-nuclear-talks-hormuz-strait-peace-may-27" target="_blank" rel="noreferrer">Fox News</a> · <a href="https://www.washingtonpost.com" target="_blank" rel="noreferrer">Washington Post</a> · <a href="https://www.straitstimes.com/world/middle-east/trump-says-us-not-satisfied-yet-on-deal-with-iran" target="_blank" rel="noreferrer">Strait Times</a> · <a href="https://www.cbsnews.com/live-updates/trump-iran-war-peace-deal-strait-of-hormuz/" target="_blank" rel="noreferrer">CBS News</a> （T: 05:00 TST）</li></ul><h3 id="_2-⛽-油價暴跌-6-wti-跌至-88-68、brent-至-92-25" tabindex="-1">2. ⛽ 油價暴跌 6%+：WTI 跌至 $88.68、Brent 至 $92.25 <a class="header-anchor" href="#_2-⛽-油價暴跌-6-wti-跌至-88-68、brent-至-92-25" aria-label="Permalink to &quot;2. ⛽ 油價暴跌 6%+：WTI 跌至 $88.68、Brent 至 $92.25&quot;">​</a></h3><ul><li><strong>下跌幅度</strong>：WTI 跌 6%+ 至 ~$88.68/bbl（五週低點），Brent 跌至 ~$92.25/bbl</li><li><strong>驅動因素</strong>：伊朗 MOU 報導引發和平希望，市場預期海峽重開將大幅增加供應。即便 Trump 否認，油價仍維持低位。</li><li><strong>Brent 日間波動</strong>：盤中一度觸及 ~$99，收盤回落至 $92-$95 區間。</li><li><strong>與3月高點比較</strong>：3月曾觸及 $120+/bbl，至今累計回落 ~25%。</li><li><strong>連鎖反應</strong>：油氣股（Exxon、Chevron）下跌，但消費股與大盤受惠油價回落。</li><li>來源：<a href="https://www.columbian.com/news/2026/may/27/wall-street-hangs-near-its-records-as-oil-prices-ease/" target="_blank" rel="noreferrer">Columbian</a> · <a href="https://www.zacks.com/stock/news/2927625/wti-crude-lowest-in-five-weeks" target="_blank" rel="noreferrer">Zacks</a> · <a href="https://www.morningstar.com/news/dow-jones/202605276881/nymex-overview-us-crude-futures-fall-on-peace-oil-flow-optimism-in-mideast-opis" target="_blank" rel="noreferrer">Morningstar</a> · <a href="https://tradingeconomics.com/commodity/brent-crude-oil" target="_blank" rel="noreferrer">TradingEconomics</a> （T: 05:00 TST）</li></ul><h3 id="_3-📈-美股三大指數同創新高-s-p-7-520-道瓊-50-644-nasdaq-26-674" tabindex="-1">3. 📈 美股三大指數同創新高：S&amp;P 7,520 / 道瓊 50,644 / Nasdaq 26,674 <a class="header-anchor" href="#_3-📈-美股三大指數同創新高-s-p-7-520-道瓊-50-644-nasdaq-26-674" aria-label="Permalink to &quot;3. 📈 美股三大指數同創新高：S&amp;P 7,520 / 道瓊 50,644 / Nasdaq 26,674&quot;">​</a></h3><ul><li><strong>S&amp;P 500</strong>：收 7,520.36（+0.16%），2026年第20次收盤新高、連續6日上漲。Goldman Sachs 上調年底目標至 8,000。</li><li><strong>道瓊</strong>：收 50,644.28（+0.4%），第10次收盤新高。受惠醫藥與消費股輪動。</li><li><strong>Nasdaq</strong>：收 26,674.73（+0.07%），第16次收盤新高。Nasdaq 100 首度突破 30,000，Micron 加入兆元市值俱樂部。</li><li><strong>油價下跌</strong>是今日股市主要推手，緩解家庭與企業成本壓力。Bath &amp; Body Works、Abercrombie &amp; Fitch 財報優於預期。</li><li>來源：<a href="https://www.kvue.com/article/syndication/associatedpress/how-major-us-stock-indexes-fared-wednesday-5272026/616-2d215978-37c8-407a-befd-c016aaac9805" target="_blank" rel="noreferrer">AP/KVUE</a> · <a href="https://www.morningstar.com/news/dow-jones/202605279486/sp-500-rises-002-to-752036-record-close-data-talk" target="_blank" rel="noreferrer">Morningstar</a> · <a href="https://www.businesstimes.com.sg/companies-markets/capital-markets-currencies/us-stocks-sp-500-nasdaq-hit-record-closing-highs-ai-optimism-micron-joins-us1-trillion-club" target="_blank" rel="noreferrer">Business Times SG</a> （T: 05:00 TST）</li></ul><hr><h2 id="📋-次要事件-第4-8點" tabindex="-1">📋 次要事件（第4-8點） <a class="header-anchor" href="#📋-次要事件-第4-8點" aria-label="Permalink to &quot;📋 次要事件（第4-8點）&quot;">​</a></h2><h3 id="_4-🥇-黃金跌破-4-500-受和談希望壓制-避險需求降溫" tabindex="-1">4. 🥇 黃金跌破 $4,500：受和談希望壓制，避險需求降溫 <a class="header-anchor" href="#_4-🥇-黃金跌破-4-500-受和談希望壓制-避險需求降溫" aria-label="Permalink to &quot;4. 🥇 黃金跌破 $4,500：受和談希望壓制，避險需求降溫&quot;">​</a></h3><ul><li><strong>XAU/USD</strong>：~$4,455/oz（日跌 ~1.82%），前收 $4,507.56</li><li><strong>COMEX 期貨</strong>：$4,482.65（Investing.com）/ $4,483.90（Google Finance）/ $4,453.45（TradingEconomics）</li><li><strong>交叉驗證</strong>：多來源一致在 $4,447-$4,484 區間，價差 ≤$37，正常範圍。取可信值 ~$4,455</li><li><strong>驅動</strong>：美伊和談 hope 壓低避險溢價；美元指數持平（~99.19）支撐有限</li><li>來源：<a href="https://coincodex.com/forex/xau-usd/" target="_blank" rel="noreferrer">CoinCodex</a> · <a href="https://www.investing.com/commodities/gold" target="_blank" rel="noreferrer">Investing.com</a> · <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">TradingEconomics</a> （T: 05:00 TST）</li></ul><h3 id="_5-🇹🇼-台股再創歷史新高-加權指數收-44-256-80-1-68" tabindex="-1">5. 🇹🇼 台股再創歷史新高：加權指數收 44,256.80（+1.68%） <a class="header-anchor" href="#_5-🇹🇼-台股再創歷史新高-加權指數收-44-256-80-1-68" aria-label="Permalink to &quot;5. 🇹🇼 台股再創歷史新高：加權指數收 44,256.80（+1.68%）&quot;">​</a></h3><ul><li><strong>TAIEX</strong>：44,256.80（+731.43，+1.68%），盤中最高 44,818.25</li><li><strong>前日比較</strong>：5/26 收 43,525.37，5/25 收 43,644.40</li><li><strong>驅動</strong>：AI 族群強勢 + 油價下跌利多消費股 + 外資持續買超</li><li>來源：<a href="https://www.businessinsider.tw/article/3139" target="_blank" rel="noreferrer">Business Insider TW</a> · <a href="https://www.taiwannews.com.tw/news/6369945" target="_blank" rel="noreferrer">Taiwan News</a> · <a href="https://money.udn.com/money/story/5607/9525160" target="_blank" rel="noreferrer">Udn Money</a> （T: 05:00 TST）</li></ul><h3 id="_6-₿-btc-回落至-75-000-附近-etf-資金外流-地緣不確定" tabindex="-1">6. ₿ BTC 回落至 $75,000 附近：ETF 資金外流 + 地緣不確定 <a class="header-anchor" href="#_6-₿-btc-回落至-75-000-附近-etf-資金外流-地緣不確定" aria-label="Permalink to &quot;6. ₿ BTC 回落至 $75,000 附近：ETF 資金外流 + 地緣不確定&quot;">​</a></h3><ul><li><strong>BTC</strong>：$74,900-$76,460（多來源），24h 跌幅 -1% 至 -3%</li><li><strong>支撐位</strong>：$72,000-$73,500 / <strong>阻力位</strong>：$80,500</li><li><strong>ETF 資金外流</strong>是近期壓力來源，地緣政治不確定性加劇波動</li><li>來源：<a href="https://coinmarketcap.com/currencies/bitcoin/" target="_blank" rel="noreferrer">CoinMarketCap</a> · <a href="https://www.coindesk.com/price/bitcoin" target="_blank" rel="noreferrer">CoinDesk</a> · <a href="https://www.kraken.com/prices/bitcoin" target="_blank" rel="noreferrer">Kraken</a> · <a href="https://www.gadgets360.com/cryptocurrency/news/bitcoin-slips-toward-usd-75600-as-etf-outflows-and-geopolitical-risks-weigh-on-markets-crypto-markets-prices-may-2026-11553694" target="_blank" rel="noreferrer">Gadgets 360</a> （T: 05:00 TST）</li></ul><h3 id="_7-💵-美元指數-tips-利率" tabindex="-1">7. 💵 美元指數 + TIPS + 利率 <a class="header-anchor" href="#_7-💵-美元指數-tips-利率" aria-label="Permalink to &quot;7. 💵 美元指數 + TIPS + 利率&quot;">​</a></h3><ul><li><strong>DXY</strong>：99.19（+0.02%），區間 99.09-99.21，持平</li><li><strong>10Y TIPS</strong>：2.10%（5/26），較 5/21 的 2.18% 下行，有利金價</li><li><strong>Fed 評論</strong>：Fed 官員對降息時程保持觀望，中東衝突推升通膨不確定性</li><li>來源：<a href="https://www.fxstreet.com/news/united-states-dollar-index-dxy-flatlines-around-9900-amid-mixed-news-from-iran-202605270932" target="_blank" rel="noreferrer">FXStreet</a> · <a href="https://tradingeconomics.com/united-states/currency" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://ycharts.com/indicators/10_year_real_treasury_rate" target="_blank" rel="noreferrer">YCharts</a> （T: 05:00 TST）</li></ul><h3 id="_8-🚢-海運指數-bdi-反彈至-3-124-近兩週高" tabindex="-1">8. 🚢 海運指數：BDI 反彈至 3,124（近兩週高） <a class="header-anchor" href="#_8-🚢-海運指數-bdi-反彈至-3-124-近兩週高" aria-label="Permalink to &quot;8. 🚢 海運指數：BDI 反彈至 3,124（近兩週高）&quot;">​</a></h3><ul><li><strong>BDI</strong>：3,124（5/27），較 5/21 的 2,964 反彈 +5.4%</li><li><strong>Capesize</strong>：日均收益 $44,314（+712），指數 5,272（+1.5%）</li><li><strong>驅動</strong>：亞洲假期後復市 + 鐵礦砂需求穩定 + 荷莫茲不確定性推高替代航線運費</li><li>來源：<a href="https://www.bigmint.co/intel/detail/baltic-dry-index-rises-following-holiday-led-trading-pause-36622" target="_blank" rel="noreferrer">BigMint</a> · <a href="https://www.bairdmaritime.com/shipping/dry-cargo/bulkers/baltic-dry-index-bounces-back-to-near-two-week-high-on-firm-demand" target="_blank" rel="noreferrer">Baird Maritime</a> · <a href="https://www.tradingview.com/news/te_news:554117:0-baltic-dry-index-at-near-2-week-high/" target="_blank" rel="noreferrer">TradingView</a> （T: 05:00 TST）</li></ul><hr><h2 id="🔮-前瞻預警-第9-10點" tabindex="-1">🔮 前瞻預警（第9-10點） <a class="header-anchor" href="#🔮-前瞻預警-第9-10點" aria-label="Permalink to &quot;🔮 前瞻預警（第9-10點）&quot;">​</a></h2><h3 id="_9-📅-本週重點-美伊-mou-簽署倒數-台股挑戰-45-000" tabindex="-1">9. 📅 本週重點：美伊 MOU 簽署倒數 + 台股挑戰 45,000 <a class="header-anchor" href="#_9-📅-本週重點-美伊-mou-簽署倒數-台股挑戰-45-000" aria-label="Permalink to &quot;9. 📅 本週重點：美伊 MOU 簽署倒數 + 台股挑戰 45,000&quot;">​</a></h3><ul><li><strong>美伊</strong>：Iran MOU 框架是否落地是本週最大變數。若成真 → 油價可能再跌 10-15%、風險偏好暴升</li><li><strong>台股</strong>：連續多日創新高，45,000 關卡近在咫尺，關注外資動向</li><li><strong>Micron 財報效應</strong>：AI 半導體需求持續強勁，Nasdaq 100 首破 30,000</li><li><strong>USDA 6月WASDE</strong>：預估稍後發布，關注大豆/玉米產量修正</li></ul><h3 id="_10-🌍-地緣風險-多線交織仍是最大變數" tabindex="-1">10. 🌍 地緣風險：多線交織仍是最大變數 <a class="header-anchor" href="#_10-🌍-地緣風險-多線交織仍是最大變數" aria-label="Permalink to &quot;10. 🌍 地緣風險：多線交織仍是最大變數&quot;">​</a></h3><ul><li><strong>美伊</strong>：MOU 框架 → Trump 否認 → 但「謹慎樂觀」暗示仍有空間</li><li><strong>以色列-真主黨</strong>：黎巴嫩持續交戰</li><li><strong>俄烏</strong>：俄羅斯持續攻擊烏克蘭</li><li><strong>UN 預測</strong>：2026年全球經濟成長降至 2.5%</li><li><strong>風險平衡</strong>：短期和平希望 vs 實際軍事行動仍在進行 → 高波動環境延續</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Iran International (2026-05-27): 伊朗宣佈 MOU 框架</li><li>Fox News (2026-05-27): Trump 否認伊朗報導</li><li>Washington Post (2026-05-27): 美伊分歧</li><li>AP/KVUE (2026-05-27): 美股三大指數收盤新高</li><li>Morningstar (2026-05-27): S&amp;P 500 第20次收盤新高</li><li>Zacks (2026-05-27): WTI 跌至五週低點</li><li>TradingEconomics (2026-05-27): Brent 油價、黃金、天然氣</li><li>CoinMarketCap/CoinDesk (2026-05-27): BTC $74,900-$76,460</li><li>Business Insider TW (2026-05-27): 台股加權指數 44,256</li><li>BigMint (2026-05-27): BDI 反彈至 3,124</li></ol>',31)])])}const u=e(n,[["render",o]]);export{m as __pageData,u as default};
